      'shaders/3d_and_hypercomplex/hypercomplex_escape_time/quaternion_julia_2d_gpu.frag',
    ];

    for (final asset in shaderAssets) {
      test('loads $asset', () async {
        final stopwatch = Stopwatch()..start();
