from pathlib import Path
import re, hashlib
root=Path('shaders/3d_and_hypercomplex')
# Simple brace-matching extractor for top-level GLSL functions.
for_name={}
for p in sorted(root.glob('**/*.frag')):
    text=p.read_text()
    for m in re.finditer(r'(?m)^(?:vec[234]|float|mat[234]|int|bool)\s+([A-Za-z0-9_]+)\s*\([^\n]*\)\s*\{', text):
        start=m.start(); i=m.end()-1; depth=0; end=i
        for j in range(i, len(text)):
            if text[j]=='{': depth+=1
            elif text[j]=='}':
                depth-=1
                if depth==0:
                    end=j+1; break
        body='\n'.join(line.rstrip() for line in text[start:end].splitlines())
        for_name.setdefault(m.group(1), []).append((p, hashlib.sha256(body.encode()).hexdigest()[:12], len(body), body))
print('Duplicate function names and body variants:')
for name, entries in sorted(for_name.items()):
    if len(entries) < 2: continue
    variants={h for _,h,_,_ in entries}
    print(f'- {name}: {len(entries)} occurrences, {len(variants)} body variant(s)')
    by={}
    for p,h,l,_ in entries: by.setdefault(h, []).append(str(p))
    for h, paths in by.items():
        print(f'  {h}: {len(paths)} file(s)')
        for path in paths:
            print(f'    {path}')
